sql_query:
SELECT "Clinical setting"
FROM clinical_trials
WHERE "Cancer type" = 'Renal cell';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Clinical setting" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Renal cell'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_setting_normalized(source_value) AS "setting_normalized"
FROM base;
